// Define RSS feeds to poll
const feeds = [
  { source_slug: 'reuters', name: 'Reuters', url: 'https://feeds.reuters.com/reuters/worldNews' },
  { source_slug: 'ft', name: 'Financial Times', url: 'https://ft.com/rss/home' },
  { source_slug: 'nikkei', name: 'Nikkei Asia', url: 'https://asia.nikkei.com/rss' },
  { source_slug: 'scmp', name: 'South China Morning Post', url: 'https://scmp.com/rss' }
];

return feeds.map(f => ({ json: f }));

// Process RSS items into article records
const items = $input.all();
const sourceInfo = $('Feed List').first().json;

const articles = items
  .filter(item => item.json.title && item.json.link)
  .slice(0, 10)
  .map(item => {
    const content = (item.json['content:encoded'] || item.json.description || item.json.title).replace(/<[^>]*>/g, '').trim();
    const excerpt = content.substring(0, 300);

    return {
      json: {
        id: `${sourceInfo.source_slug}-${Buffer.from(item.json.link).toString('base64').substring(0, 20)}`,
        article_id: crypto.randomUUID(),
        title: item.json.title,
        url: item.json.link,
        content: content,
        excerpt: excerpt,
        source: sourceInfo.name,
        source_slug: sourceInfo.source_slug,
        published_at: item.json.pubDate || new Date().toISOString()
      }
    };
  });

return articles.length > 0 ? articles : [{ json: { _skip: true } }];
